select.where:
 and guid = #{guid}
 and scada_data = #{scadaData}
 and serial_numbers = #{serialNumbers}
 and device_name like concat('%', #{deviceName}, '%')
 and is_main_page = #{isMainPage}
 and page_name like concat('%', #{pageName}, '%')
 and page_resolution = #{pageResolution}
 and is_share = #{isShare}
 and share_url = #{shareUrl}
 and share_pass = #{sharePass}
 and page_image = #{pageImage}
 and tenant_id = #{tenantId}
 and tenant_name like concat('%', #{tenantName}, '%')
and type = #{type}
order by create_time desc

mapper.select:
select
(select count(distinct d.device_id,d.tenant_id) from iot_device d
d.del_flag = '0'
and d.tenant_id in
#{tenantId}
) as deviceCount,
(select count(distinct d.device_id,d.tenant_id) from iot_device d
d.status=3 and d.del_flag = '0'
and d.tenant_id in
#{tenantId}
) as deviceOnlineCount,
(
select count(distinct product_id) from iot_device where user_id = #{userId} and del_flag = '0'
select count(product_id) from iot_product
del_flag = '0' and tenant_id in
#{tenantId}
) as productCount,
(select count(distinct l.serial_number) from iot_alert_log l left join iot_device d on l.serial_number=d.serial_number and d.del_flag = '0'
and d.tenant_id in
#{tenantId}
) as alertDeviceCount,
(select count(distinct d.device_id,d.tenant_id) from iot_device d
d.status=4 and d.del_flag = '0'
and d.tenant_id in
#{tenantId}
) as deviceOfflineCount,
(select count(distinct l.serial_number) from iot_alert_log l left join iot_device d on l.serial_number=d.serial_number and d.del_flag = '0'
where l.status = 2
and d.tenant_id in
#{tenantId}
) as alertNotProcessedCount,
(select count(distinct l.serial_number) from iot_alert_log l left join iot_device d on l.serial_number=d.serial_number and d.del_flag = '0'
where l.status = 3
and d.tenant_id in
#{tenantId}
) as alertProcessedCount,
(select count(distinct alert_log_id) from iot_alert_log l left join iot_device d on l.serial_number=d.serial_number and d.del_flag = '0'
and d.tenant_id in
#{tenantId}
) as alertCount

select fun_value as value,
create_time as time,
identify as identity
from iot_function_log


        and serial_number = #{serialNumber}


        and create_time between #{beginTime} and #{endTime}


        and identify in

            #{identify}



order by create_time desc

select log_value as value,
create_time as time,
identify as identity
from iot_event_log


        and serial_number = #{serialNumber}


        and create_time between #{params.beginTime} and #{params.endTime}


        and identify in

            #{identify}



order by create_time desc

select p.guid from iot_product p
where p.product_id = #{productId}
  and p.del_flag = '0'


where id in

        #{id}

    and del_flag = 0

select sd.scene_model_device_id , smd.name scene_model_device_name, sd.source_name model_name, sd.identifier, d.serial_number, d.product_id, sd.variable_type, sd.type, sd.unit, smd.scene_model_id from scene_model_data sd left join scene_model_device smd on sd.scene_model_device_id = smd.id left join iot_device d on smd.cus_device_id = d.device_id where sd.del_flag = 0 and sd.enable = 1 and sd.scene_model_id = #{sceneModelId}
and sd.source_name like concat('%', #{modelName}, '%')
and sd.scene_model_device_id = #{sceneModelDeviceId}
order by sd.variable_type asc, sd.id desc limit #{pageStart},#{size}

select guid, scene_model_id from scene_model where guid in
#{guid}
and del_flag = 0

select guid, product_id from iot_product where guid in
#{guid}
and del_flag = 0

select d.serial_number
from scene_model_device smd join iot_device d on smd.cus_device_id = d.device_id and d.del_flag = '0'
where smd.id = #{sceneModelDeviceId}

select count(1) from scene_model_data sd left join scene_model_device smd on sd.scene_model_device_id = smd.id left join iot_device d on smd.cus_device_id = d.device_id and d.del_flag = '0' where sd.del_flag = 0 and sd.enable = 1 and sd.scene_model_id = #{sceneModelId}
and sd.source_name like concat('%', #{modelName}, '%')
and sd.scene_model_device_id = #{sceneModelDeviceId}

select smd.source_name modelName, smd.identifier, smd.scene_model_id, smd.scene_model_device_id, smd.variable_type, smd.type, sm.name sceneModelDeviceName,
       d.serial_number, d.product_id, d.device_name, d.status
from scene_model_data smd left join scene_model_device sm on smd.scene_model_device_id = sm.id
left join iot_device d on sm.cus_device_id = d.device_id and d.del_flag = '0'
where smd.identifier in

        #{identifier}


    and smd.scene_model_device_id = #{sceneModelDeviceId}

and smd.scene_model_id = #{sceneModelId}
and smd.del_flag = 0

select fun_value value, create_time ts
from iot_function_log
where identify in

        #{identifier}


    and create_time between #{beginTime} and #{endTime}

order by create_time desc

mapper.update:
update iot_product
set guid = #{guid}
where product_id = #{productId}

update scene_model
set guid = #{guid}
where scene_model_id = #{sceneModelId}

update scada
set is_share = #{isShare},
    share_url = #{shareUrl},
    share_pass = #{sharePass},
    share_short_url = #{shareShortUrl}
where guid = #{guid}
